/*
 * TICKET NORMALISER
 * ──────────────────────────────────────────────────────────────────
 * Accepts payloads from: direct form, Zendesk, Intercom, Freshdesk.
 * Stamps urgency pre-signal for AI context injection.
 */

const raw = $input.first().json.body ?? $input.first().json;

// ── Field normalisation ────────────────────────────────────────────
const subject = (raw.subject ?? raw.title ?? '').trim();
const body    = (raw.body ?? raw.description ?? raw.message ?? '').trim();
const combined = `${subject} ${body}`.toLowerCase();

// ── Deterministic pre-signals (seeded into AI prompt) ─────────────
const PRE_SIGNALS = {
  hasUrgencyKeyword:  /urgent|critical|down|broken|emergency|asap|immediately|not working|crashed|data loss|outage/i.test(combined),
  hasLegalKeyword:    /lawsuit|attorney|legal action|sue|chargeback|fraud|gdpr|data breach/i.test(combined),
  hasBillingKeyword:  /invoice|charge|payment|refund|subscription|billing|overcharged/i.test(combined),
  hasSecurityKeyword: /hacked|compromised|unauthorized|breach|vulnerability|exploit/i.test(combined)
};

const traceId  = `tr-ticket-${Date.now().toString(36)}`;
const ticketId = raw.ticketId ?? raw.id ?? `TKT-${Date.now()}`;

return [{
  json: {
    traceId,
    ticketId,
    subject,
    body:          body.length > 3000 ? body.slice(0, 3000) + '…' : body,
    customerEmail: (raw.email ?? raw.customerEmail ?? '').toLowerCase().trim(),
    customerName:  raw.name  ?? raw.customerName  ?? 'Customer',
    source:        raw.source ?? 'webhook',
    preSignals:    PRE_SIGNALS,
    metadata: {
      accountId: raw.accountId ?? null,
      planType:  raw.planType  ?? 'unknown',
      userAgent: raw.userAgent ?? null
    },
    submittedAt: new Date().toISOString()
  }
}];

