/*
 * CLASSIFICATION ENRICHER + BUSINESS RULE ENFORCEMENT
 * ──────────────────────────────────────────────────────────────────
 * Defensive JSON parse → apply deterministic overrides → validate output.
 * Business rules always supersede AI — this is the safety guarantee.
 */

const ticket = $input.all()[0].json;
const aiText = $input.all()[1]?.json?.message?.content ?? '{}';

// ── Safe parse ────────────────────────────────────────────────────
let cls;
try {
  cls = JSON.parse(aiText.replace(/```json|```/g, '').trim());
} catch (_e) {
  cls = {
    category: 'general', subcategory: 'unclassified',
    priority: 'P3_medium', sla_minutes: 240,
    sentiment: 'neutral', frustrationScore: 5,
    assignedTeam: 'general_support',
    escalate: true, escalationReason: 'AI_PARSE_FAILURE',
    keyIssues: ['Classification failed'], suggestedFirstResponse: 'Thank you for reaching out. We are reviewing your ticket.',
    confidence: 0.0
  };
}

// ── Deterministic enforcement rules ──────────────────────────────
const p = ticket.preSignals;
const plan = ticket.metadata.planType?.toLowerCase();

// Security trumps everything
if (p.hasSecurityKeyword) {
  cls.priority       = 'P1_critical';
  cls.sla_minutes    = 15;
  cls.assignedTeam   = 'security';
  cls.escalate       = true;
  cls.escalationReason = 'SECURITY_KEYWORD_DETECTED';
}
// Legal language forces review
if (p.hasLegalKeyword) {
  cls.escalate       = true;
  cls.escalationReason = cls.escalationReason ?? 'LEGAL_LANGUAGE_DETECTED';
  if (!['P1_critical','P2_high'].includes(cls.priority)) {
    cls.priority     = 'P2_high';
    cls.sla_minutes  = 60;
  }
}
// Urgency keyword floors at P2
if (p.hasUrgencyKeyword && !['P1_critical','P2_high'].includes(cls.priority)) {
  cls.priority       = 'P2_high';
  cls.sla_minutes    = 60;
  cls.escalationReason = cls.escalationReason ?? 'URGENCY_KEYWORD_DETECTED';
}
// Enterprise P1/P2 always escalates
if (['enterprise','enterprise_plus'].includes(plan) && ['P1_critical','P2_high'].includes(cls.priority)) {
  cls.escalate       = true;
  cls.escalationReason = cls.escalationReason ?? `ENTERPRISE_${cls.priority}`;
}

// ── SLA deadline ──────────────────────────────────────────────────
const slaDeadline = new Date(Date.now() + cls.sla_minutes * 60 * 1000).toISOString();

return [{
  json: {
    ...ticket,
    classification: cls,
    slaDeadline,
    routingKey: `${cls.assignedTeam}::${cls.priority}`
  }
}];

// P1 Slack Block Kit — oncall pager-level alert
const t = $input.first().json;
const c = t.classification;
return [{
  json: {
    ...t,
    slackBlocks: [
      { type: 'header', text: { type: 'plain_text', text: '🚨 P1 CRITICAL — IMMEDIATE RESPONSE REQUIRED', emoji: true } },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Ticket:*\n\`${t.ticketId}\`` },
          { type: 'mrkdwn', text: `*Customer:*\n${t.customerName}` },
          { type: 'mrkdwn', text: `*Plan:*\n${t.metadata.planType}` },
          { type: 'mrkdwn', text: `*SLA Deadline:*\n${t.slaDeadline}` },
          { type: 'mrkdwn', text: `*Category:*\n${c.category} / ${c.subcategory}` },
          { type: 'mrkdwn', text: `*Team:*\n${c.assignedTeam}` }
        ]
      },
      { type: 'section', text: { type: 'mrkdwn', text: `*Subject:*\n${t.subject}` } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Key Issues:*\n${c.keyIssues.map(i => `• ${i}`).join('\n')}` } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Escalation Reason:*\n${c.escalationReason ?? 'None'}` } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Suggested First Response:*\n${c.suggestedFirstResponse}` } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: `Trace: \`${t.traceId}\` | Frustration: ${c.frustrationScore}/10 | Confidence: ${(c.confidence * 100).toFixed(0)}%` }] },
      { type: 'divider' }
    ],
    slackChannel: '#oncall-p1-alerts'
  }
}];

// P2+ Slack Block Kit — team channel alert
const t = $input.first().json;
const c = t.classification;
const EMOJI = { P2_high: '🔴', P3_medium: '🟡', P4_low: '🟢' };
return [{
  json: {
    ...t,
    slackBlocks: [
      {
        type: 'section',
        text: { type: 'mrkdwn', text: `${EMOJI[c.priority] ?? '📋'} *${c.priority} Ticket* — ${c.category}/${c.subcategory}\n*${t.customerName}* (${t.customerEmail}) | Plan: ${t.metadata.planType}\nSLA: ${t.slaDeadline}` }
      },
      { type: 'section', text: { type: 'mrkdwn', text: `*Subject:* ${t.subject}\n*Issues:* ${c.keyIssues.join(' · ')}` } },
      { type: 'context', elements: [{ type: 'mrkdwn', text: `Ticket: \`${t.ticketId}\` | Team: ${c.assignedTeam} | Trace: \`${t.traceId}\`` }] }
    ],
    slackChannel: `#support-${c.assignedTeam.replace('_', '-')}`
  }
}];
